mapper.update:
UPDATE board
SET title = #{title}, content = #{content}
WHERE boardno = #{boardno}

UPDATE board
SET cnt = cnt + 1
WHERE boardno = #{boardno}

UPDATE board
SET recom = recom + 1
WHERE boardno = #{boardno}

UPDATE contents
SET recom = recom - 1
WHERE boardno = #{boardno}

mapper.select:
SELECT boardno, categoryno, memberno, title, content, passwd, word, rdate, visible, cnt, file1, file1saved, thumb1, size1, recom, r FROM ( SELECT boardno, categoryno, memberno, title, content, passwd, word, rdate, visible, cnt, file1, file1saved, thumb1, size1, recom, rownum as r FROM ( SELECT boardno, categoryno, memberno, title, content, passwd, word, rdate, visible, cnt, file1, file1saved, thumb1, size1, recom FROM board
WHERE categoryno=#{categoryno}
WHERE categoryno=#{categoryno} AND (UPPER(title) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(content) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(word) LIKE '%' || UPPER(#{word}) || '%')
ORDER BY boardno DESC ) ) WHERE r >= #{start_num} AND r <= #{end_num}

SELECT COUNT(*) as cnt FROM board
WHERE categoryno=#{categoryno}
WHERE categoryno=#{categoryno} AND (UPPER(title) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(content) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(word) LIKE '%' || UPPER(#{word}) || '%')

SELECT * FROM ( SELECT boardno, categoryno, memberno, title, content, passwd, word, rdate, visible, cnt, file1, file1saved, thumb1, size1, recom, rownum as r FROM ( SELECT boardno, categoryno, memberno, title, content, passwd, word, rdate, visible, cnt, file1, file1saved, thumb1, size1, recom FROM board
WHERE UPPER(title) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(content) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(word) LIKE '%' || UPPER(#{word}) || '%'
ORDER BY boardno DESC ) ) WHERE r >= #{start_num} AND r <= #{end_num}
